// postActionExpr builds a datastar @post action expression that sends
// `payload` as a JSON body. `payload` is a JS object-literal expression
// (e.g. `{on: true}`, `{manual: evt.target.valueAsNumber}`); pass empty
// string for no body.
//
// @post (rather than raw fetch()) lets datastar process the SSE-event
// stream the handler returns on error, which is how
// #global-error-banner gets populated for auth/UDP failures.
//
// Both branches go through datastar.PostSSE for URL formatting /
// escaping; the with-payload form wraps the result with
// withDatastarOpts because the SDK helper doesn't model action options.
func postActionExpr(url, payload string) string {
	base := datastar.PostSSE("%s", url)
	if payload == "" {
		return base
	}
	return withDatastarOpts(base, fmt.Sprintf("{payload: %s}", payload))
}

// controlsEditAttr returns the data-attr:data-edit expression for the
// controls panel. Reads the per-device $editor.<name> signal so opening
// the preset editor on one card doesn't flip data-edit="true" on every
// other card. See #29-class bugs.
func controlsEditAttr(name string) string {
	return fmt.Sprintf("$editor.%s !== 0 ? 'true' : null", name)
}

// attentionIfOff wraps a click expression with an "if device is off,
// glow the power button" prefix. Flips the per-device transient
// $_attention.<name> signal, which the power button's data-class binding
// consumes. The 1200 ms timeout is aligned with the CSS animation's
// 2-iteration × 0.6 s alternate cycle (one full out-and-back pulse) so
// class removal happens at the natural animation end (ring at zero).
//
// The wrapped expression always runs after — sending the @post against
// an off device is harmless and matches the prior behaviour (buttons
// were never click-disabled when off).
func attentionIfOff(name, expr string) string {
	return fmt.Sprintf(
		"if (!$power.%s) { $_attention.%s = true; setTimeout(() => { $_attention.%s = false; }, 1200); } %s",
		name, name, name, expr,
	)
}

// presetSliderExpr builds the data-on:change expression for a preset
// editor slider. Reads the per-side signal (data-bind two-way binding
// keeps it current with the input value), applies snap-to-zero (1..9 →
// 0), mirrors to the other side when $matchSpeeds.<name>, then posts
// /preset when both sides are ≥10 and /mode when the implied airflow
// mode differs from the device's current mode. Errors from either POST
// flow through datastar's SSE error envelope into #global-error-banner.
//
// All four editor signals ($editor, $preset, $automode, $matchSpeeds)
// are scoped per-device under <name> so dragging on one card does not
// move another card's slider in lockstep.
func presetSliderExpr(name string, n int, side string) string {
	var setSelf, setMatch string
	if side == "supply" {
		setSelf = fmt.Sprintf("$preset.%s[%d].supply = v;", name, n)
		setMatch = fmt.Sprintf("if ($matchSpeeds.%s) $preset.%s[%d].extract = v;", name, name, n)
	} else {
		setSelf = fmt.Sprintf("$preset.%s[%d].extract = v;", name, n)
		setMatch = fmt.Sprintf("if ($matchSpeeds.%s) $preset.%s[%d].supply = v;", name, name, n)
	}
	postPreset := postActionExpr(
		fmt.Sprintf("/ui/devices/%s/preset", name),
		fmt.Sprintf("{preset: %d, supply: sup, extract: ext}", n),
	)
	postMode := postActionExpr(
		fmt.Sprintf("/ui/devices/%s/mode", name),
		"{mode: implied}",
	)
	return fmt.Sprintf(
		`let raw = parseInt(evt.target.value, 10); `+
			`if (isNaN(raw)) raw = 0; `+
			`raw = Math.max(0, Math.min(100, raw)); `+
			`let v = (raw > 0 && raw < 10) ? 0 : raw; `+
			`evt.target.value = v; `+
			`%s %s `+
			`let sup = $preset.%s[%d].supply, ext = $preset.%s[%d].extract; `+
			`if (sup >= 10 && ext >= 10) `+
			`%s; `+
			`let implied = null; `+
			`if ($automode.%s) implied = 'ventilation'; `+
			`else if (sup >= 10 && ext >= 10) implied = 'regeneration'; `+
			`else if (sup === 0 && ext >= 10) implied = 'extract'; `+
			`else if (sup >= 10 && ext === 0) implied = 'supply'; `+
			`if (implied && $speedMode.%s === 'preset%d' && $airflowMode.%s !== implied) `+
			`%s;`,
		setSelf, setMatch, name, n, name, n, postPreset, name, name, n, name, postMode,
	)
}

// matchSpeedsMirrorExpr returns the data-on:input handler that mirrors
// the dragged/typed side to its counterpart when $matchSpeeds.<name> is
// true. Fires on every input event (slider drag, number-input keystroke)
// so the other side tracks live rather than jumping at release. Reads
// evt.target.value directly to avoid depending on data-bind's
// signal-write ordering. The change handler (presetSliderExpr) still
// runs on release/blur for snap-to-zero, mirror with snapped value, and
// the actual POST — this handler is purely visual feedback during drag.
func matchSpeedsMirrorExpr(name string, n int, side string) string {
	other := "extract"
	if side == "extract" {
		other = "supply"
	}
	return fmt.Sprintf(
		"if ($matchSpeeds.%s) $preset.%s[%d].%s = parseInt(evt.target.value, 10);",
		name, name, n, other,
	)
}

// presetSliderValue returns the slider's value attribute, treating the
// "-1 = unknown" sentinel (PresetView pre-poll) as 50 (mid-range fallback)
// so the thumb sits somewhere reasonable before the first poll lands.
func presetSliderValue(pct int) string {
	if pct < 0 {
		return "50"
	}
	return fmt.Sprintf("%d", pct)
}

// timerGroupCloseEditorEffect builds the data-effect expression that
// closes the duration editor whenever $specialMode.<name> no longer
// matches the currently-open editor. Catches every closure path
// with one rule: cascade-driven (preset/manual click), power-off,
// scheduler-driven deactivation, server-pushed mode change (another
// client switched night↔turbo). The 'off' guard avoids self-write
// loops when the editor is already closed.
func timerGroupCloseEditorEffect(name string) string {
	return fmt.Sprintf(
		"if ($durationEditor.%s !== 'off' && $durationEditor.%s !== $specialMode.%s) $durationEditor.%s = 'off'",
		name, name, name, name,
	)
}

